+    if (std.mem.indexOf(u8, compressed, "image/gif")) |_| {
+        std.debug.print("✅ Contains GIF image!\n", .{});
+        
+        // Extract and save first GIF for inspection
+        if (std.mem.indexOf(u8, compressed, "\"data\":\"")) |start| {
+            const data_start = start + 8;
