+                std.debug.print("✅ Saved to /tmp/extracted.gif ({d} bytes)\n", .{gif_bytes.len});
+            }
+        }
+    } else {
+        std.debug.print("❌ No GIF found - kept as text\n", .{});
+    }
+}

